import DashboardLayout from "./layouts/DashboardLayout";
import StatCard from "./components/StatCard";
import SectionHeader from "./components/SectionHeader";




export default function Dashboard() {
    return (
        <DashboardLayout>
            <SectionHeader title="Overview" />

            <div className="stats-grid">
                <StatCard label="Total Matches" value="1,284" />
                <StatCard label="Active Teams" value="96" />
                <StatCard label="Players Tracked" value="1,432" />
                <StatCard label="Events" value="54" />
            </div>

            <SectionHeader title="Latest News" action="Create" />
            {/* News table goes here */}

            <SectionHeader title="Recent Threads" action="New Thread" />
            {/* Threads table goes here */}
        </DashboardLayout>
    );
}
